import argparse
import json
import os
import numpy as np
import heapq
import torch
from cogniplan_env import ExplorationEnv


def dijkstra(adj, start):
    N = len(adj)
    dist = [float('inf')] * N
    prev = [None] * N
    dist[start] = 0.0
    pq = [(0.0, start)]
    while pq:
        d, u = heapq.heappop(pq)
        if d > dist[u] + 1e-9:
            continue
        for v, w in adj[u]:
            nd = d + w
            if nd + 1e-9 < dist[v]:
                dist[v] = nd
                prev[v] = u
                heapq.heappush(pq, (nd, v))
    return dist, prev


def round_coord(c):
    return tuple(np.round(np.array(c, dtype=float), 6))


def build_graph(nodes, robot_pos, neighbors):
    coord_to_idx = {}
    for i, n in enumerate(nodes):
        coord_to_idx[round_coord(n["coords"])] = i
    N = len(nodes)
    adj = [[] for _ in range(N)]
    for i, n in enumerate(nodes):
        for nb in n.get("neighbors", []):
            j = None
            if isinstance(nb, dict):
                nb = nb.get("coords", nb)
            if isinstance(nb, (list, tuple, np.ndarray)):
                j = coord_to_idx.get(round_coord(nb))
            else:
                try:
                    j = int(nb)
                    if not (0 <= j < N):
                        j = None
                except (ValueError, TypeError):
                    j = None
            if j is not None and j != i:
                w = float(np.linalg.norm(
                    np.array(n["coords"], dtype=float) -
                    np.array(nodes[j]["coords"], dtype=float)
                ))
                adj[i].append((j, w))
    r_idx = N
    adj.append([])
    for nb in neighbors:
        j = coord_to_idx.get(round_coord(nb))
        if j is None:
            continue
        w = float(np.linalg.norm(
            np.array(robot_pos, dtype=float) -
            np.array(nb, dtype=float)
        ))
        adj[r_idx].append((j, w))
        adj[j].append((r_idx, w))
    return adj, coord_to_idx, r_idx


class SimpleGreedyPlanner:
    def __init__(self, dist_denom=1.0, visited_penalty=0.95, reverse_penalty=0.3,
                 history_penalty=0.95, history_len=10):
        self.dist_denom = dist_denom
        self.visited_penalty = visited_penalty
        self.reverse_penalty = reverse_penalty
        self.history_penalty = history_penalty
        self.history_len = history_len
        self.reset()

    def reset(self):
        self.step_count = 0
        self.prev_pos = None
        self.history = []

    def plan(self, obs):
        self.step_count += 1
        robot_pos = np.array(obs["robot_pos"], dtype=float)
        neighbors = obs["neighbors"]
        nodes = obs["nodes"]
        frontiers = obs.get("frontiers", [])

        if not neighbors:
            return None

        adj, coord_to_idx, r_idx = build_graph(nodes, robot_pos, neighbors)
        dist, prev = dijkstra(adj, r_idx)
        N = len(nodes)

        node_to_nb = {}
        for idx, nb in enumerate(neighbors):
            j = coord_to_idx.get(round_coord(nb))
            if j is not None:
                node_to_nb[j] = idx

        first_step = {}
        for j in range(N):
            if dist[j] == float('inf') or prev[j] is None:
                continue
            cur = j
            depth = 0
            while prev[cur] != r_idx and prev[cur] is not None and depth < N + 5:
                cur = prev[cur]
                depth += 1
            if prev[cur] == r_idx and cur in node_to_nb:
                first_step[j] = node_to_nb[cur]

        remaining_steps = 128 - self.step_count

        reverse_idx = None
        if self.prev_pos is not None:
            prev_vec = robot_pos - np.array(self.prev_pos, dtype=float)
            prev_norm = np.linalg.norm(prev_vec)
            if prev_norm > 0.01:
                best_dot = float('inf')
                for idx, nb in enumerate(neighbors):
                    nb_vec = np.array(nb, dtype=float) - robot_pos
                    dot = np.dot(prev_vec, nb_vec)
                    if dot < best_dot:
                        best_dot = dot
                        reverse_idx = idx

        best_score = -float('inf')
        best_j = None

        for j in range(N):
            if j not in first_step:
                continue
            utility = float(nodes[j].get("utility", 0.0))
            if utility <= 0:
                continue
            d = dist[j]
            score = utility / (d + self.dist_denom)
            if nodes[j].get("visited", False):
                score *= self.visited_penalty
            if j in self.history:
                score *= self.history_penalty
            idx = first_step[j]
            if idx == reverse_idx:
                score *= self.reverse_penalty
            est_steps = max(d / 3.2, 1.0)
            if est_steps > remaining_steps:
                continue
            if score > best_score:
                best_score = score
                best_j = j

        # Fallback 1: move toward nearest frontier
        if best_j is None and frontiers:
            best_fscore = -float('inf')
            for j in range(N):
                if j not in first_step:
                    continue
                node_pos = np.array(nodes[j]["coords"], dtype=float)
                min_fd = min(np.linalg.norm(node_pos - np.array(f, dtype=float)) for f in frontiers)
                fscore = 1.0 / (min_fd + dist[j] + 1.0)
                if nodes[j].get("visited", False):
                    fscore *= 0.5
                if j in self.history:
                    fscore *= 0.8
                if fscore > best_fscore:
                    best_fscore = fscore
                    best_j = j

        # Fallback 2: nearest unvisited node
        if best_j is None:
            best_d = float('inf')
            for j in range(N):
                if j not in first_step:
                    continue
                if nodes[j].get("visited", False):
                    continue
                if dist[j] < best_d:
                    best_d = dist[j]
                    best_j = j

        # Fallback 3: nearest any node
        if best_j is None:
            best_d = float('inf')
            for j in range(N):
                if j not in first_step:
                    continue
                if dist[j] < best_d:
                    best_d = dist[j]
                    best_j = j

        if best_j is None:
            return neighbors[0] if neighbors else None

        self.prev_pos = robot_pos.copy()
        self.history.append(best_j)
        if len(self.history) > self.history_len:
            self.history.pop(0)

        return neighbors[first_step[best_j]]


def run_episode(env, planner):
    obs = env.reset()
    planner.reset()
    for _ in range(128):
        target = planner.plan(obs)
        if target is None:
            break
        obs, info = env.step(target)
        if info.get("done", False):
            break
    return env.get_metrics()


def get_eval_maps(data_path):
    eval_config_path = os.path.join(data_path, "eval_config.json")
    episodes = []
    if os.path.exists(eval_config_path):
        with open(eval_config_path) as f:
            config = json.load(f)
        if isinstance(config, dict) and "episodes" in config:
            for ep in config["episodes"]:
                episodes.append({
                    "map_path": os.path.join(data_path, ep["map"]),
                    "env_type": ep.get("type", "unknown")
                })

    if not episodes:
        maps_dir = os.path.join(data_path, "maps_eval")
        for env_type in ["room", "tunnel", "outdoor"]:
            type_dir = os.path.join(maps_dir, env_type)
            if not os.path.isdir(type_dir):
                continue
            for fname in sorted(os.listdir(type_dir)):
                if fname.endswith(".png"):
                    episodes.append({
                        "map_path": os.path.join(type_dir, fname),
                        "env_type": env_type
                    })
    return episodes


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--data_path", required=True)
    parser.add_argument("--checkpoint", required=True)
    parser.add_argument("--output", required=True)
    args = parser.parse_args()

    ckpt_path = os.path.join(args.checkpoint, "policy.pt")
    if os.path.exists(ckpt_path):
        ckpt = torch.load(ckpt_path, map_location="cpu")
    else:
        ckpt = {}

    episodes = get_eval_maps(args.data_path)
    planner = SimpleGreedyPlanner()

    per_episode = []
    per_type_lists = {}

    for ep in episodes:
        env = ExplorationEnv(map_path=ep["map_path"])
        metrics = run_episode(env, planner)
        success = 1 if metrics.get("success", False) else 0
        distance = metrics.get("travel_distance", 0.0)
        explored = metrics.get("explored_rate", 0.0)

        result = {
            "map_path": os.path.relpath(ep["map_path"], args.data_path),
            "env_type": ep["env_type"],
            "success": success,
            "travel_distance": distance,
            "explored_rate": explored
        }
        per_episode.append(result)

        et = ep["env_type"]
        if et not in per_type_lists:
            per_type_lists[et] = []
        per_type_lists[et].append(result)

    total_episodes = len(per_episode)
    explored_rate = sum(e["explored_rate"] for e in per_episode) / total_episodes
    success_rate = sum(e["success"] for e in per_episode) / total_episodes
    successful_distances = [e["travel_distance"] for e in per_episode if e["success"]]
    travel_distance = sum(successful_distances) / len(successful_distances) if successful_distances else 0.0

    per_type = {}
    for et, ress in per_type_lists.items():
        count = len(ress)
        succ_dists = [r["travel_distance"] for r in ress if r["success"]]
        per_type[et] = {
            "explored_rate": sum(r["explored_rate"] for r in ress) / count,
            "travel_distance": sum(succ_dists) / len(succ_dists) if succ_dists else 0.0,
            "success_rate": sum(r["success"] for r in ress) / count
        }

    out = {
        "explored_rate": explored_rate,
        "travel_distance": travel_distance,
        "success_rate": success_rate,
        "per_episode": per_episode,
        "per_type": per_type,
        "total_episodes": total_episodes
    }

    os.makedirs(os.path.dirname(args.output), exist_ok=True)
    with open(args.output, "w") as f:
        json.dump(out, f, indent=2)


if __name__ == "__main__":
    main()
